                      {form.compiler === c.value && <div className="h-2 w-2 rounded-full bg-white" />}
                    </div>
                    <div>
                      <p className="text-sm font-medium text-text">{c.label}</p>
                      <p className="text-xs text-text-muted">{c.description}</p>
