export class AgentExecutor {
  private activeExecutions = new Map<string, boolean>()

  async execute(context: AgentExecutionContext, callbacks: AgentStreamCallback): Promise<AgentExecutionResult> {
    const bridge = bridgeRegistry.get(context.bridgeName)
    if (!bridge) {
      const error = `Bridge "${context.bridgeName}" not found`
      await this.failSession(context.sessionId, error)
      callbacks.onError(error)
      return { status: 'failed', output: '', error }
    }

    if (!bridge.isAvailable()) {
      const error = `Bridge "${context.bridgeName}" is not available`
      await this.failSession(context.sessionId, error)
      callbacks.onError(error)
      return { status: 'failed', output: '', error }
    }

    this.activeExecutions.set(context.sessionId, true)

    await db
      .update(agentSessions)
      .set({ status: 'running', updatedAt: new Date() })
      .where(eq(agentSessions.id, context.sessionId))

    callbacks.onStatus('running')
    await this.addLog(context.sessionId, 'status', 'Execution started')

    try {
      const result = await bridge.streamResponse(
        {
          sessionId: context.sessionId,
          projectId: context.projectId,
          prompt: context.prompt,
        },
        (event) => {
          if (!this.activeExecutions.get(context.sessionId)) return

          switch (event.type) {
            case 'output':
              callbacks.onOutput(event.content)
              break
            case 'error':
              callbacks.onError(event.content)
              break
            case 'status':
              callbacks.onLog('bridge', event.content)
              break
            case 'complete':
              callbacks.onLog('bridge', event.content)
              break
          }
        },
      )

      if (!this.activeExecutions.get(context.sessionId)) {
        return { status: 'cancelled', output: '' }
      }

      await db.insert(agentMessages).values({
        sessionId: context.sessionId,
        role: 'agent',
        content: result.output,
      })

      await db
        .update(agentSessions)
        .set({ status: 'completed', updatedAt: new Date() })
        .where(eq(agentSessions.id, context.sessionId))

      await this.addLog(context.sessionId, 'status', 'Execution completed')

      const executionResult: AgentExecutionResult = {
        status: 'completed',
        output: result.output,
      }

      callbacks.onComplete(executionResult)
      this.activeExecutions.delete(context.sessionId)
      return executionResult
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : 'Unknown error'
      await this.failSession(context.sessionId, errorMessage)
      callbacks.onError(errorMessage)
      this.activeExecutions.delete(context.sessionId)
      return { status: 'failed', output: '', error: errorMessage }
    }
  }

  async cancel(sessionId: string): Promise<void> {
    this.activeExecutions.delete(sessionId)

    const bridges = bridgeRegistry.getAll()
    for (const bridge of bridges) {
      await bridge.cancelExecution(sessionId)
    }

    await db
      .update(agentSessions)
      .set({ status: 'cancelled', updatedAt: new Date() })
      .where(eq(agentSessions.id, sessionId))

    await this.addLog(sessionId, 'status', 'Execution cancelled')
  }

  isRunning(sessionId: string): boolean {
    return this.activeExecutions.get(sessionId) === true
  }

  private async failSession(sessionId: string, error: string): Promise<void> {
    await db
      .update(agentSessions)
      .set({ status: 'failed', updatedAt: new Date() })
      .where(eq(agentSessions.id, sessionId))

    await this.addLog(sessionId, 'error', error)
  }

  private async addLog(sessionId: string, logType: string, message: string): Promise<void> {
    await db.insert(agentLogs).values({ sessionId, logType, message })
  }
}

export const agentExecutor = new AgentExecutor()

import type { FastifyInstance } from 'fastify'
import { z } from 'zod'
import { eq, and, desc } from 'drizzle-orm'
import { db } from '../db/index.js'
import { projects } from '../db/schema/projects.js'
import { agentSessions } from '../db/schema/agent-sessions.js'
import { agentMessages } from '../db/schema/agent-messages.js'
import { agentLogs } from '../db/schema/agent-logs.js'
import { authMiddleware } from '../middleware/auth.js'

const sendMessageSchema = z.object({
  content: z.string().min(1).max(10000),
})

async function verifyProjectOwnership(userId: string, projectId: string) {
  const [project] = await db
    .select({ id: projects.id })
    .from(projects)
    .where(and(eq(projects.id, projectId), eq(projects.userId, userId)))
    .limit(1)
  return project
}

export async function agentRoutes(app: FastifyInstance) {
  // List agent sessions for a project
  app.get('/api/projects/:projectId/agent/sessions', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId } = request.params as { projectId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const sessions = await db
      .select()
      .from(agentSessions)
      .where(eq(agentSessions.projectId, projectId))
      .orderBy(desc(agentSessions.createdAt))

    return sessions
  })

  // Create a new agent session
  app.post('/api/projects/:projectId/agent/sessions', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId } = request.params as { projectId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [session] = await db
      .insert(agentSessions)
      .values({ projectId })
      .returning()

    return reply.status(201).send(session)
  })

  // Get a specific agent session with its messages
  app.get('/api/projects/:projectId/agent/sessions/:sessionId', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId, sessionId } = request.params as { projectId: string; sessionId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [session] = await db
      .select()
      .from(agentSessions)
      .where(and(eq(agentSessions.id, sessionId), eq(agentSessions.projectId, projectId)))
      .limit(1)

    if (!session) {
      return reply.status(404).send({ message: 'Session not found', statusCode: 404 })
    }

    const messages = await db
      .select()
      .from(agentMessages)
      .where(eq(agentMessages.sessionId, sessionId))
      .orderBy(agentMessages.createdAt)

    return { ...session, messages }
  })

  // Send a message to an agent session
  app.post('/api/projects/:projectId/agent/sessions/:sessionId/messages', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId, sessionId } = request.params as { projectId: string; sessionId: string }
    const parsed = sendMessageSchema.safeParse(request.body)
    if (!parsed.success) {
      return reply.status(400).send({
        message: parsed.error.issues[0].message,
        statusCode: 400,
      })
    }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [session] = await db
      .select()
      .from(agentSessions)
      .where(and(eq(agentSessions.id, sessionId), eq(agentSessions.projectId, projectId)))
      .limit(1)

    if (!session) {
      return reply.status(404).send({ message: 'Session not found', statusCode: 404 })
    }

    const [message] = await db
      .insert(agentMessages)
      .values({
        sessionId,
        role: 'user',
        content: parsed.data.content,
      })
      .returning()

    await db
      .update(agentSessions)
      .set({ status: 'running', updatedAt: new Date() })
      .where(eq(agentSessions.id, sessionId))

    return reply.status(201).send(message)
  })

  // Cancel an agent session
  app.post('/api/projects/:projectId/agent/sessions/:sessionId/cancel', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId, sessionId } = request.params as { projectId: string; sessionId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const [session] = await db
      .select()
      .from(agentSessions)
      .where(and(eq(agentSessions.id, sessionId), eq(agentSessions.projectId, projectId)))
      .limit(1)

    if (!session) {
      return reply.status(404).send({ message: 'Session not found', statusCode: 404 })
    }

    if (session.status !== 'running' && session.status !== 'idle') {
      return reply.status(400).send({ message: 'Session is not active', statusCode: 400 })
    }

    const [updated] = await db
      .update(agentSessions)
      .set({ status: 'cancelled', updatedAt: new Date() })
      .where(eq(agentSessions.id, sessionId))
      .returning()

    await db.insert(agentLogs).values({
      sessionId,
      logType: 'status',
      message: 'Session cancelled by user',
    })

    return updated
  })

  // Get logs for a session
  app.get('/api/projects/:projectId/agent/sessions/:sessionId/logs', { preHandler: [authMiddleware] }, async (request, reply) => {
    const { projectId, sessionId } = request.params as { projectId: string; sessionId: string }

    const project = await verifyProjectOwnership(request.user!.id, projectId)
    if (!project) {
      return reply.status(404).send({ message: 'Project not found', statusCode: 404 })
    }

    const logs = await db
      .select()
      .from(agentLogs)
      .where(eq(agentLogs.sessionId, sessionId))
      .orderBy(agentLogs.createdAt)

    return logs
  })
}

