import type { BridgeInterface, BridgeTask, BridgeResult, BridgeStreamEvent } from './types.js'

export class OpenCodeBridge implements BridgeInterface {
  name = 'opencode'
  private activeSessions = new Map<string, AbortController>()

  async initialize(): Promise<void> {
    // OpenCode runtime initialization will be implemented here
  }

  async executeTask(task: BridgeTask): Promise<BridgeResult> {
    // Placeholder: OpenCode execution will be wired up in the AI integration phase
