---

### 1. Installation

```bash
npm install @opencode-ai/sdk
```

---

### 2. Import and Create Client

You can create a client (and optionally a server) instance:

```typescript
import { createOpencode, createOpencodeClient } from "@opencode-ai/sdk";

// Create both client and server (starts server on localhost:4096 by default)
const { client, server } = await createOpencode({
  hostname: "127.0.0.1",
  port: 4096,
  config: {
    model: "anthropic/claude-3-5-sonnet-20241022", // example model
  },
});

// Or create client only to connect to an existing server
const clientOnly = createOpencodeClient({
  baseUrl: "http://127.0.0.1:4096",
});
```

---

### 3. Types Import

Import types for sessions, messages, and parts:

```typescript
import type { Session, Message, Part } from "@opencode-ai/sdk";
```

---

### 4. Sessions API

- **List sessions**

```typescript
const sessions: Session[] = await client.session.list();
```

- **Create a session**

```typescript
const newSession: Session = await client.session.create({
  name?: string; // optional session name
  config?: object; // optional session config overrides
});
```

- **Get a session by ID**

```typescript
const session: Session = await client.session.get(sessionId: string);
```

---

### 5. Messages API

- **Send a message to a session**

```typescript
const message: Message = await client.message.create({
  sessionId: string;
  content: string;
  role?: "user" | "assistant" | "system"; // optional role, default "user"
});
```

- **List messages in a session**

```typescript
const messages: Message[] = await client.message.list(sessionId: string);
```

---

### 6. Streaming Responses

The SDK supports streaming responses via async iterators (Server Sent Events):

```typescript
const stream = await client.message.stream({
  sessionId: string;
  content: string;
  role?: "user" | "assistant" | "system";
});

for await (const part of stream) {
  // part is of type Part
  console.log(part.text); // partial text response
  // You can break or abort the stream if needed
}
```

- To cancel a stream, break the loop or call `stream.controller.abort()`.

---

### 7. File Operations

The SDK exposes file operations (read, list, glob, grep) as tools accessible via the client:

```typescript
// Example: list files in a directory
const files: string[] = await client.file.list({
  path: string; // directory path
});

// Read file content
const content: string = await client.file.read({
  path: string; // file path
});

// Glob files matching a pattern
const matchedFiles: string[] = await client.file.glob({
  pattern: string; // glob pattern
});

// Grep content in files
const grepResults: Array<{ path: string; line: number; text: string }> = await client.file.grep({
  pattern: string; // search pattern
  path?: string; // optional directory path
});
```

---

### 8. Example Usage

```typescript
import { createOpencode } from "@opencode-ai/sdk";

async function main() {
  const { client, server } = await createOpencode({
    hostname: "127.0.0.1",
    port: 4096,
    config: { model: "anthropic/claude-3-5-sonnet-20241022" },
  });

  // Create a new session
  const session = await client.session.create({ name: "My Session" });

  // Send a message and receive streaming response
  const stream = await client.message.stream({
    sessionId: session.id,
    content: "Explain the use of context in Go",
  });

  for await (const part of stream) {
    process.stdout.write(part.text);
  }

  // File operations example
  const files = await client.file.list({ path: "." });
  console.log("Files:", files);

  // Close server when done
  server.close();
}

main();
```

---

### Summary of Key Function Signatures

```typescript
// Create client and server
async function createOpencode(options?: {
  hostname?: string;
  port?: number;
  signal?: AbortSignal;
  timeout?: number;
  config?: object;
}): Promise<{ client: OpencodeClient; server: OpencodeServer }>;

// Create client only
function createOpencodeClient(options: { baseUrl: string }): OpencodeClient;

// Session APIs
interface OpencodeClient {
  session: {
    list(): Promise<Session[]>;
    create(params: { name?: string; config?: object }): Promise<Session>;
    get(sessionId: string): Promise<Session>;
  };
