  pattern: string; // search pattern
  path?: string; // optional directory path
});
```

---

### 8. Example Usage

```typescript
import { createOpencode } from "@opencode-ai/sdk";

async function main() {
  const { client, server } = await createOpencode({
    hostname: "127.0.0.1",
    port: 4096,
    config: { model: "anthropic/claude-3-5-sonnet-20241022" },
  });

